 360	func collectParseErrorDetails(root *sitter.Node, src []byte, limit, lineOffset int) []string {
 361		if root == nil || root.IsNull() || limit <= 0 {
 362			return nil
 363		}
 364		var details []string
 365		var walk func(*sitter.Node)
 366		walk = func(node *sitter.Node) {
 367			if node == nil || node.IsNull() || len(details) >= limit {
 368				return
 369			}
 370			if node.IsError() || node.IsMissing() {
 371				point := node.StartPoint()
 372				kind := "error"
 373				if node.IsMissing() {
 374					kind = "missing"
 375				}
 376				snippet := strings.TrimSpace(node.Content(src))
 377				if snippet == "" {
 378					snippet = strings.TrimSpace(sourceLineAt(src, int(point.Row)+1))
 379				}
 380				if len(snippet) > 80 {
 381					snippet = snippet[:80] + "..."
 382				}
 383				line := int(point.Row) + 1 - lineOffset
 384				if line < 1 {
 385					line = 1
 386				}
 387				details = append(details, fmt.Sprintf("%s %s at line %d column %d near %q", kind, node.Type(), line, point.Column+1, snippet))
 388			}
 389			for i := 0; i < int(node.ChildCount()) && len(details) < limit; i++ {
 390				walk(node.Child(i))
 391			}
 392		}
 393		walk(root)
 394		return details
 395	}
