+	requireNoTSParseError(t, "types.ts", "// Auto-generated database schema types.\nexport type * from \"./schema\"\n")
+}
+
+// Import-type references without `typeof` вҖ” `import("./types").Foo["k"]` in a
+// type position вҖ” are rejected by the grammar (entire.io github.ts, shiki
+// module declarations).
